import React, { useState } from 'react';
import { Link } from 'react-router-dom';
import './Categories.css';

const CATEGORIES = [
  {
    name: 'Necklaces', count: '48 items', icon: '📿',
    img: 'https://images.unsplash.com/photo-1599643478518-a784e5dc4c8f?w=600&q=80&auto=format',
  },
  {
    name: 'Rings', count: '64 items', icon: '💍',
    img: 'https://images.unsplash.com/photo-1605100804763-247f67b3557e?w=600&q=80&auto=format',
  },
  {
    name: 'Earrings', count: '52 items', icon: '✨',
    img: 'https://images.unsplash.com/photo-1535632066927-ab7c9ab60908?w=600&q=80&auto=format',
  },
  {
    name: 'Bracelets', count: '36 items', icon: '⭕',
    img: 'https://images.unsplash.com/photo-1611591437281-460bfbe1220a?w=600&q=80&auto=format',
  },
];

function CategoryCard({ cat }) {
  const [imgError, setImgError] = useState(false);
  return (
    <Link to="/shop" className="category-card">
      {imgError ? (
        <div className="category-img-tile" style={{ background: '#fff0e6' }}>
          <span className="category-tile-icon">{cat.icon}</span>
        </div>
      ) : (
        <img
          src={cat.img}
          alt={cat.name}
          className="category-img"
          crossOrigin="anonymous"
          onError={() => setImgError(true)}
        />
      )}
      <div className="category-overlay">
        <span className="category-icon">{cat.icon}</span>
        <span className="category-name">{cat.name}</span>
        <span className="category-count">{cat.count}</span>
      </div>
    </Link>
  );
}

function Categories() {
  return (
    <section className="categories-section">
      <h2 className="section-title">Shop by Category</h2>
      <div className="gold-divider"></div>
      <p className="section-subtitle">Explore our curated jewellery collections</p>
      <div className="categories-grid">
        {CATEGORIES.map((cat) => (
          <CategoryCard key={cat.name} cat={cat} />
        ))}
      </div>
    </section>
  );
}

export default Categories;
